1	'use client';
2	
3	import { useRef, useState, useEffect, useCallback } from 'react';
4	
5	type Metric = 'euclidean' | 'manhattan' | 'chebyshev' | 'minkowski3' | 'minkowski05';
6	
7	const METRICS: Metric[] = ['minkowski05', 'manhattan', 'euclidean', 'minkowski3', 'chebyshev'];
8	const METRIC_LABEL: Record<Metric, string> = {
9	  euclidean: 'L2', manhattan: 'L1', chebyshev: 'L∞', minkowski3: 'L3', minkowski05: 'L½',
10	};
11	const METRIC_DESC: Record<Metric, string> = {
12	  euclidean:   'euclidean (circular)',
13	  manhattan:   'manhattan (diamond)',
14	  chebyshev:   'chebyshev (square)',
15	  minkowski3:  'minkowski p=3 (rounded square)',
16	  minkowski05: 'minkowski p=½ (star)',
17	};
18	const METRIC_INDEX: Record<Metric, number> = {
19	  euclidean: 0, manhattan: 1, chebyshev: 2, minkowski3: 3, minkowski05: 4,
20	};
21	
22	interface Site {
23	  id: string;
24	  x: number; y: number;
25	  metric: Metric;
26	  r: number; g: number; b: number;
27	}
28	
29	function metricDistJS(m: Metric, ax: number, ay: number): number {
30	  switch (m) {
31	    case 'euclidean':   return Math.sqrt(ax * ax + ay * ay);
32	    case 'manhattan':   return ax + ay;
33	    case 'chebyshev':   return Math.max(ax, ay);
34	    case 'minkowski3':  return Math.cbrt(ax * ax * ax + ay * ay * ay);
35	    case 'minkowski05': { const s = Math.sqrt(ax) + Math.sqrt(ay); return s * s; }
36	  }
37	}
38	
39	function hslToRgb(h: number, s: number, l: number): [number, number, number] {
40	  s /= 100; l /= 100;
41	  const k = (n: number) => (n + h / 30) % 12;
42	  const a = s * Math.min(l, 1 - l);
43	  const f = (n: number) => l - a * Math.max(-1, Math.min(k(n) - 3, Math.min(9 - k(n), 1)));
44	  return [Math.round(f(0) * 255), Math.round(f(8) * 255), Math.round(f(4) * 255)];
45	}
46	
47	// ── WebGL shaders ─────────────────────────────────────────────────────────────
48	
49	const VERT = `#version 300 es
50	in vec2 a_pos;
51	void main() { gl_Position = vec4(a_pos, 0.0, 1.0); }
52	`;
53	
54	// Fragment shader: per-pixel Voronoi with smooth anti-aliased borders.
55	// Each site has its own distance metric; boundaries are where two sites tie.
56	// The gap between d1 (nearest) and d2 (second-nearest) is 0 exactly on the
57	// boundary and grows away from it — used for smooth border darkening.
58	const FRAG = `#version 300 es
59	precision highp float;
60	
61	const int MAX = 64;
62	
63	uniform vec2  u_res;
64	uniform int   u_n;
65	uniform vec2  u_sites[MAX];
66	uniform vec3  u_colors[MAX];
67	uniform int   u_metrics[MAX];
68	
69	out vec4 fragColor;
70	
71	float vdist(int m, float ax, float ay) {
72	  if (m == 0) return sqrt(ax*ax + ay*ay);          // L2  euclidean
73	  if (m == 1) return ax + ay;                       // L1  manhattan
74	  if (m == 2) return max(ax, ay);                   // L∞  chebyshev
75	  if (m == 3) return pow(ax*ax*ax + ay*ay*ay, 1.0/3.0); // L3
76	  float s = sqrt(ax) + sqrt(ay); return s*s;        // L½  minkowski
77	}
78	
79	void main() {
80	  if (u_n == 0) { fragColor = vec4(0.0); return; }
81	
82	  // gl_FragCoord origin is bottom-left; sites are top-left CSS coords × dpr
83	  vec2 p = vec2(gl_FragCoord.x, u_res.y - gl_FragCoord.y);
84	
85	  float d1 = 1e9, d2 = 1e9;
86	  int owner = 0;
87	
88	  for (int i = 0; i < MAX; i++) {
89	    if (i >= u_n) break;
90	    float d = vdist(u_metrics[i], abs(p.x - u_sites[i].x), abs(p.y - u_sites[i].y));
91	    if (d < d1) { d2 = d1; d1 = d; owner = i; }
92	    else if (d < d2) { d2 = d; }
93	  }
94	
95	  // Convert gap from metric units to pixel distance by dividing by the gradient
96	  // magnitude. dFdx/dFdy give adjacent-fragment differences for free on the GPU.
97	  // Without this, borders widen where the gap opens slowly (oblique boundaries
98	  // between different metrics) and narrow where it opens fast.
99	  float gap = d2 - d1;
100	  float grad = length(vec2(dFdx(gap), dFdy(gap)));
101	  float borderDist = gap / max(grad, 1e-6);
102	  float border = smoothstep(0.0, 1.5, borderDist);
103	  fragColor = vec4(u_colors[owner] * mix(0.22, 1.0, border), 1.0);
104	}
105	`;
106	
107	function compileShader(gl: WebGL2RenderingContext, type: number, src: string) {
108	  const s = gl.createShader(type)!;
109	  gl.shaderSource(s, src); gl.compileShader(s);
110	  return s;
111	}
112	
113	let nextId = 0;
114	
115	export function VoronoiCanvas() {
116	  // Two stacked canvases: WebGL for Voronoi cells, 2D for site markers.
117	  const glCanvasRef     = useRef<HTMLCanvasElement>(null);
118	  const markerCanvasRef = useRef<HTMLCanvasElement>(null);
119	  const containerRef    = useRef<HTMLDivElement>(null);
120	
121	  // WebGL state
122	  const glRef   = useRef<WebGL2RenderingContext | null>(null);
123	  const progRef = useRef<WebGLProgram | null>(null);
124	  const uRef    = useRef<Record<string, WebGLUniformLocation | null>>({});
125	
126	  const sitesRef      = useRef<Site[]>([]);
127	  const selectedIdRef = useRef<string | null>(null);
128	
129	  const [sites, setSitesState]   = useState<Site[]>([]);
130	  const [selectedId, setSelectedId] = useState<string | null>(null);
131	  const [currentMetric, setCurrentMetric] = useState<Metric>('euclidean');
132	  const [mousePos, setMousePos] = useState<{ x: number; y: number } | null>(null);
133	  const siteCount = useRef(0);
134	
135	  const dragRef = useRef<{
136	    id: string; startMouseX: number; startMouseY: number;
137	    origX: number; origY: number; moved: boolean;
138	  } | null>(null);
139	  const mouseDownOnSite = useRef(false);
140	
141	  const commitSites = useCallback((next: Site[]) => {
142	    sitesRef.current = next;
143	    setSitesState(next);
144	  }, []);
145	
146	  // ── WebGL init ──────────────────────────────────────────────────────────────
147	  useEffect(() => {
148	    const canvas = glCanvasRef.current;
149	    if (!canvas) return;
150	    const gl = canvas.getContext('webgl2', { alpha: true, premultipliedAlpha: false });
151	    if (!gl) return;
152	    glRef.current = gl;
153	
154	    const prog = gl.createProgram()!;
155	    gl.attachShader(prog, compileShader(gl, gl.VERTEX_SHADER, VERT));
156	    gl.attachShader(prog, compileShader(gl, gl.FRAGMENT_SHADER, FRAG));
157	    gl.linkProgram(prog);
158	    gl.useProgram(prog);
159	    progRef.current = prog;
160	
161	    // Fullscreen quad (two triangles)
162	    const buf = gl.createBuffer();
163	    gl.bindBuffer(gl.ARRAY_BUFFER, buf);
164	    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([
165	      -1, -1,  1, -1,  -1,  1,
166	      -1,  1,  1, -1,   1,  1,
167	    ]), gl.STATIC_DRAW);
168	    const loc = gl.getAttribLocation(prog, 'a_pos');
169	    gl.enableVertexAttribArray(loc);
170	    gl.vertexAttribPointer(loc, 2, gl.FLOAT, false, 0, 0);
171	
172	    uRef.current = {
173	      res:     gl.getUniformLocation(prog, 'u_res'),
174	      n:       gl.getUniformLocation(prog, 'u_n'),
175	      sites:   gl.getUniformLocation(prog, 'u_sites'),
176	      colors:  gl.getUniformLocation(prog, 'u_colors'),
177	      metrics: gl.getUniformLocation(prog, 'u_metrics'),
178	    };
179	  }, []);
180	
181	  // ── Render ──────────────────────────────────────────────────────────────────
182	  const renderGL = useCallback(() => {
183	    const gl   = glRef.current;
184	    const prog = progRef.current;
185	    const u    = uRef.current;
186	    const canvas = glCanvasRef.current;
187	    if (!gl || !prog || !canvas) return;
188	
189	    const dpr   = window.devicePixelRatio || 1;
190	    const sites = sitesRef.current;
191	
192	    gl.viewport(0, 0, canvas.width, canvas.height);
193	    gl.uniform2f(u.res, canvas.width, canvas.height);
194	    gl.uniform1i(u.n, sites.length);
195	
196	    if (sites.length > 0) {
197	      const sv = new Float32Array(sites.length * 2);
198	      const cv = new Float32Array(sites.length * 3);
199	      const mv = new Int32Array(sites.length);
200	      for (let i = 0; i < sites.length; i++) {
201	        sv[i * 2]     = sites[i].x * dpr;
202	        sv[i * 2 + 1] = sites[i].y * dpr;
203	        cv[i * 3]     = sites[i].r / 255;
204	        cv[i * 3 + 1] = sites[i].g / 255;
205	        cv[i * 3 + 2] = sites[i].b / 255;
206	        mv[i]         = METRIC_INDEX[sites[i].metric];
207	      }
208	      gl.uniform2fv(u.sites,   sv);
209	      gl.uniform3fv(u.colors,  cv);
210	      gl.uniform1iv(u.metrics, mv);
211	    }
212	
213	    gl.drawArrays(gl.TRIANGLES, 0, 6);
214	  }, []);
215	
216	  const renderMarkers = useCallback(() => {
217	    const canvas = markerCanvasRef.current;
218	    if (!canvas) return;
219	    const ctx = canvas.getContext('2d');
220	    if (!ctx) return;
221	
222	    const dpr   = window.devicePixelRatio || 1;
223	    const sites = sitesRef.current;
224	    const selId = selectedIdRef.current;
225	
226	    ctx.clearRect(0, 0, canvas.width, canvas.height);
227	    ctx.save();
228	    ctx.scale(dpr, dpr);
229	
230	    for (const site of sites) {
231	      if (site.id === selId) {
232	        ctx.beginPath();
233	        ctx.arc(site.x, site.y, 11, 0, Math.PI * 2);
234	        ctx.strokeStyle = '#fff';
235	        ctx.lineWidth   = 2.5;
236	        ctx.stroke();
237	        ctx.beginPath();
238	        ctx.arc(site.x, site.y, 11, 0, Math.PI * 2);
239	        ctx.strokeStyle = 'rgba(0,0,0,0.4)';
240	        ctx.lineWidth   = 1;
241	        ctx.stroke();
242	      }
243	
244	      ctx.beginPath();
245	      ctx.arc(site.x, site.y, 6, 0, Math.PI * 2);
246	      ctx.fillStyle = 'rgba(0,0,0,0.45)';
247	      ctx.fill();
248	
249	      ctx.beginPath();
250	      ctx.arc(site.x, site.y, 4, 0, Math.PI * 2);
251	      ctx.fillStyle = '#fff';
252	      ctx.fill();
253	
254	      ctx.font      = 'bold 11px ui-monospace, monospace';
255	      ctx.fillStyle = 'rgba(0,0,0,0.7)';
256	      ctx.fillText(METRIC_LABEL[site.metric], site.x + 9, site.y + 4);
257	    }
258	
259	    ctx.restore();
260	  }, []);
261	
262	  const render = useCallback(() => {
263	    renderGL();
264	    renderMarkers();
265	  }, [renderGL, renderMarkers]);
266	
267	  // ── Resize ──────────────────────────────────────────────────────────────────
268	  const resizeCanvases = useCallback(() => {
269	    const container = containerRef.current;
270	    if (!container) return;
271	    const dpr = window.devicePixelRatio || 1;
272	    const w   = container.clientWidth;
273	    const h   = container.clientHeight;
274	    for (const c of [glCanvasRef.current, markerCanvasRef.current]) {
275	      if (!c) continue;
276	      c.width        = w * dpr;
277	      c.height       = h * dpr;
278	      c.style.width  = `${w}px`;
279	      c.style.height = `${h}px`;
280	    }
281	    render();
282	  }, [render]);
283	
284	  useEffect(() => {
285	    resizeCanvases();
286	    const obs = new ResizeObserver(resizeCanvases);
287	    if (containerRef.current) obs.observe(containerRef.current);
288	    return () => obs.disconnect();
289	  }, [resizeCanvases]);
290	
291	  useEffect(() => {
292	    sitesRef.current = sites;
293	    render();
294	  }, [sites, render]);
295	
296	  // ── Interaction helpers ──────────────────────────────────────────────────────
297	  const getPos = (e: React.MouseEvent) => {
298	    const r = glCanvasRef.current!.getBoundingClientRect();
299	    return { x: e.clientX - r.left, y: e.clientY - r.top };
300	  };
301	
302	  const findNear = (x: number, y: number, r = 14): Site | null => {
303	    let best: Site | null = null, bestD = r;
304	    for (const s of sitesRef.current) {
305	      const d = Math.hypot(s.x - x, s.y - y);
306	      if (d < bestD) { bestD = d; best = s; }
307	    }
308	    return best;
309	  };
310	
311	  // ── Event handlers ───────────────────────────────────────────────────────────
312	  const onMouseDown = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
313	    if (e.button !== 0) return;
314	    const { x, y } = getPos(e);
315	    const near = findNear(x, y);
316	    if (near) {
317	      selectedIdRef.current = near.id;
318	      setSelectedId(near.id);
319	      dragRef.current = { id: near.id, startMouseX: x, startMouseY: y, origX: near.x, origY: near.y, moved: false };
320	      mouseDownOnSite.current = true;
321	      renderMarkers();
322	    } else {
323	      selectedIdRef.current = null;
324	      setSelectedId(null);
325	      mouseDownOnSite.current = false;
326	      dragRef.current = null;
327	      renderMarkers();
328	    }
329	  }, [renderMarkers]);
330	
331	  const onMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
332	    const container = containerRef.current!;
333	    const { x, y } = getPos(e);
334	    setMousePos({ x, y });
335	    if (!dragRef.current) {
336	      container.style.cursor = findNear(x, y) ? 'grab' : 'crosshair';
337	      return;
338	    }
339	    const drag = dragRef.current;
340	    const dx = x - drag.startMouseX, dy = y - drag.startMouseY;
341	    if (!drag.moved && (Math.abs(dx) > 3 || Math.abs(dy) > 3)) {
342	      drag.moved = true;
343	      container.style.cursor = 'grabbing';
344	    }
345	    if (!drag.moved) return;
346	    const canvas = glCanvasRef.current!;
347	    const nx = Math.max(0, Math.min(canvas.clientWidth,  drag.origX + dx));
348	    const ny = Math.max(0, Math.min(canvas.clientHeight, drag.origY + dy));
349	    sitesRef.current = sitesRef.current.map(s => s.id === drag.id ? { ...s, x: nx, y: ny } : s);
350	    render();
351	  }, [render]);
352	
353	  const onMouseUp = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
354	    if (e.button !== 0) return;
355	    containerRef.current!.style.cursor = 'crosshair';
356	    if (dragRef.current) {
357	      if (dragRef.current.moved) setSitesState([...sitesRef.current]);
358	      dragRef.current = null;
359	      return;
360	    }
361	    if (!mouseDownOnSite.current) {
362	      const { x, y } = getPos(e);
363	      const hue = (siteCount.current * 137.508) % 360;
364	      const [r, g, b] = hslToRgb(hue, 60, 68);
365	      const id = String(nextId++);
366	      siteCount.current++;
367	      const newSite: Site = { id, x, y, metric: currentMetric, r, g, b };
368	      selectedIdRef.current = id;
369	      setSelectedId(id);
370	      commitSites([...sitesRef.current, newSite]);
371	    }
372	  }, [currentMetric, commitSites]);
373	
374	  const onContextMenu = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
375	    e.preventDefault();
376	    const { x, y } = getPos(e);
377	    const near = findNear(x, y);
378	    if (!near) return;
379	    if (selectedIdRef.current === near.id) { selectedIdRef.current = null; setSelectedId(null); }
380	    commitSites(sitesRef.current.filter(s => s.id !== near.id));
381	  }, [commitSites]);
382	
383	  const applyMetric = useCallback((m: Metric) => {
384	    setCurrentMetric(m);
385	    if (selectedIdRef.current) {
386	      commitSites(sitesRef.current.map(s => s.id === selectedIdRef.current ? { ...s, metric: m } : s));
387	    }
388	  }, [commitSites]);
389	
390	  const activeMetric = selectedId
391	    ? (sites.find(s => s.id === selectedId)?.metric ?? currentMetric)
392	    : currentMetric;
393	
394	  // Per-site distances at the current mouse position, for the toolbar annotation.
395	  const hover = mousePos && sites.length > 0
396	    ? sites.map(s => ({
397	        s,
398	        d: metricDistJS(s.metric, Math.abs(mousePos.x - s.x), Math.abs(mousePos.y - s.y)),
399	      }))
400	    : null;
401	  const hoverMin = hover ? Math.min(...hover.map(h => h.d)) : Infinity;
402	
403	  return (
404	    <div style={{ display: 'flex', flexDirection: 'column', height: '100dvh', background: 'var(--bg)' }}>
405	      {/* ── main toolbar row ── */}
406	      <div style={{
407	        display: 'flex', alignItems: 'center', gap: '0.75rem',
408	        padding: '0.6rem 1rem', borderBottom: '1px solid var(--border)',
409	        fontSize: '0.85rem', fontFamily: 'var(--mono)',
410	      }}>
411	        <a href="/" style={{ color: 'var(--muted)', textDecoration: 'none' }}>←</a>
412	        <span style={{ fontWeight: 'bold' }}>voronoi</span>
413	        <span style={{ color: 'var(--border)' }}>|</span>
414	
415	        {METRICS.map(m => (
416	          <button key={m} onClick={() => applyMetric(m)} title={METRIC_DESC[m]} style={{
417	            background: activeMetric === m ? 'var(--accent)' : 'none',
418	            border:     `1px solid ${activeMetric === m ? 'var(--accent)' : 'var(--border)'}`,
419	            color:      activeMetric === m ? '#fff' : 'var(--fg)',
420	            fontFamily: 'var(--mono)', fontSize: '0.8rem',
421	            padding: '0.15rem 0.55rem', cursor: 'pointer', borderRadius: '2px',
422	          }}>
423	            {METRIC_LABEL[m]}
424	          </button>
425	        ))}
426	
427	        <span style={{ color: 'var(--muted)', fontSize: '0.75rem', marginLeft: 'auto' }}>
428	          {selectedId ? 'drag · change metric · right-click removes' : 'click to place · right-click removes'}
429	        </span>
430	        <button onClick={() => { selectedIdRef.current = null; setSelectedId(null); siteCount.current = 0; commitSites([]); }} style={{
431	          background: 'none', border: '1px solid var(--border)', color: 'var(--muted)',
432	          fontFamily: 'var(--mono)', fontSize: '0.85rem', padding: '0.1rem 0.6rem', cursor: 'pointer',
433	        }}>clear</button>
434	      </div>
435	
436	      {/* ── hover annotation row (always visible for stable layout) ── */}
437	      <div style={{
438	        display: 'flex', alignItems: 'center', flexWrap: 'nowrap',
439	        gap: '0.3rem 0.75rem',
440	        padding: '0 1rem', borderBottom: '1px solid var(--border)',
441	        fontSize: '0.78rem', fontFamily: 'var(--mono)', lineHeight: 1,
442	        height: '1.9rem', overflow: 'hidden',
443	      }}>
444	        {hover && (
445	          <>
446	            <span style={{ color: 'var(--muted)', whiteSpace: 'nowrap' }}>
447	              ({Math.round(mousePos!.x)}, {Math.round(mousePos!.y)})
448	            </span>
449	            <span style={{ color: 'var(--border)' }}>·</span>
450	            {hover.map(({ s, d }) => {
451	              const winner = d === hoverMin;
452	              return (
453	                <span key={s.id} style={{
454	                  display: 'inline-flex', alignItems: 'center', gap: '0.25rem',
455	                  color: winner ? 'var(--fg)' : 'var(--muted)',
456	                  fontWeight: winner ? 'bold' : 'normal',
457	                  whiteSpace: 'nowrap',
458	                }}>
459	                  <span style={{
460	                    display: 'inline-block', width: '7px', height: '7px',
461	                    borderRadius: '50%', flexShrink: 0,
462	                    background: `rgb(${s.r},${s.g},${s.b})`,
463	                    boxShadow: winner ? '0 0 0 1.5px var(--fg)' : 'none',
464	                  }} />
465	                  <span style={{ color: 'var(--muted)', fontSize: '0.72rem' }}>{METRIC_LABEL[s.metric]}</span>
466	                  {Math.round(d)}
467	                  {winner && <span style={{ color: 'var(--accent)' }}>◀</span>}
468	                </span>
469	              );
470	            })}
471	          </>
472	        )}
473	      </div>
474	
475	      <div
476	        ref={containerRef}
477	        style={{ flex: 1, overflow: 'hidden', position: 'relative', cursor: 'crosshair' }}
478	        onMouseDown={onMouseDown}
479	        onMouseMove={onMouseMove}
480	        onMouseUp={onMouseUp}
481	        onMouseLeave={() => setMousePos(null)}
482	        onContextMenu={onContextMenu}
483	      >
484	        {/* WebGL canvas: Voronoi cells at full physical resolution */}
485	        <canvas ref={glCanvasRef} style={{ position: 'absolute', inset: 0, display: 'block' }} />
486	        {/* 2D canvas: site markers (transparent, non-interactive) */}
487	        <canvas ref={markerCanvasRef} style={{ position: 'absolute', inset: 0, display: 'block', pointerEvents: 'none' }} />
488	
489	        {sites.length === 0 && (
490	          <div style={{
491	            position: 'absolute', inset: 0,
492	            display: 'flex', alignItems: 'center', justifyContent: 'center',
493	            flexDirection: 'column', gap: '0.4rem',
494	            color: 'var(--muted)', fontFamily: 'var(--mono)', pointerEvents: 'none',
495	          }}>
496	            <span>click to place points</span>
497	            <span style={{ fontSize: '0.75rem' }}>each point uses its own distance metric</span>
498	          </div>
499	        )}
500	      </div>
501	    </div>
502	  );
503	}
504

